import UIKit
import Alamofire

class TradeViewController: UIViewController {
    @IBOutlet weak var stockSymbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var priceLabel: UILabel!

    override func viewDidLoad() {
        super.viewDidLoad()
    }

    @IBAction func executeTrade(_ sender: UIButton) {
        guard let symbol = stockSymbolTextField.text, let quantityStr = quantityTextField.text, let quantity = Int(quantityStr) else {
            return
        }

        fetchStockPrice(symbol) { price in
            if let price = price {
                let totalValue = price * Double(quantity)
                self.priceLabel.text = "Total Value: \(totalValue)"
                // Execute trade logic here
                self.executeTradeAPI(symbol, quantity, price, totalValue)
            }
        }
    }

    private func fetchStockPrice(_ symbol: String, completion: @escaping (Double?) -> Void) {
        let url = "https://api.example.com/stock/\(symbol)/price"
        Alamofire.request(url).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let price = value as? Double {
                    completion(price)
                } else {
                    completion(nil)
                }
            case .failure(_):
                completion(nil)
            }
        }
    }

    private func executeTradeAPI(_ symbol: String, _ quantity: Int, _ price: Double, _ totalValue: Double) {
        let url = "https://api.example.com/trade"
        let parameters: [String: Any] = [
            "symbol": symbol,
            "quantity": quantity,
            "price": price,
            "totalValue": totalValue
        ]
        Alamofire.request(url, method: .post, parameters: parameters, encoding: JSONEncoding.default, headers: nil).responseJSON { response in
            switch response.result {
            case .success(_):
                // Handle successful trade execution
                print("Trade executed successfully")
            case .failure(let error):
                print("Failed to execute trade: \(error)")
            }
        }
    }
}

class PortfolioViewController: UIViewController {
    @IBOutlet weak var tableView: UITableView!
    private var stocks = [Stock]()

    override func viewDidLoad() {
        super.viewDidLoad()
        tableView.dataSource = self
        tableView.delegate = self
        fetchPortfolioData()
    }

    private func fetchPortfolioData() {
        let url = "https://api.example.com/portfolio"
        Alamofire.request(url).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let data = value as? [[String: Any]] {
                    self.stocks = data.map { Stock(symbol: $0["symbol"] as! String, quantity: $0["quantity"] as! Int, price: $0["price"] as! Double) }
                    DispatchQueue.main.async {
                        self.tableView.reloadData()
                    }
                }
            case .failure(let error):
                print("Failed to fetch portfolio data: \(error)")
            }
        }
    }
}

extension PortfolioViewController: UITableViewDataSource, UITableViewDelegate {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return stocks.count
    }

    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "StockCell", for: indexPath)
        let stock = stocks[indexPath.row]
        cell.textLabel?.text = "\(stock.symbol) - \(stock.quantity) shares"
        cell.detailTextLabel?.text = "Price: \(stock.price), Total Value: \(stock.totalValue)"
        return cell
    }
}

struct Stock {
    let symbol: String
    let quantity: Int
    let price: Double
    var totalValue: Double {
        return Double(quantity) * price
    }
}